UPDATE catalog_node
SET sort = sort - 1
WHERE parent_id = #{parentId} AND sort > #{afterSort}

UPDATE catalog_node
SET sort = sort + 1
WHERE parent_id = #{parentId} AND sort >= #{fromSort}

UPDATE catalog_node
SET sort = sort - 1
WHERE parent_id = #{parentId}
  AND sort BETWEEN #{fromSort} AND #{toSort}
  AND id != #{excludeId}

UPDATE catalog_node
SET sort = sort + 1
WHERE parent_id = #{parentId}
  AND sort BETWEEN #{fromSort} AND #{toSort}
  AND id != #{excludeId}
